import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { User, AuthContextType } from '../types';
import { authService } from '../services/apiService';

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

interface AuthProviderProps {
  children: React.ReactNode;
}

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  // Prevent double-fetch in React 18 StrictMode (dev only)
  const hasInitializedRef = useRef(false);

  useEffect(() => {
    if (hasInitializedRef.current) return;
    hasInitializedRef.current = true;
    const token = localStorage.getItem('token');
    console.log('AuthContext: Token found:', !!token);
    if (token) {
      authService.getCurrentUser()
        .then(userData => {
          console.log('AuthContext: User loaded:', userData);
          setUser(userData);
        })
        .catch((error) => {
          console.log('AuthContext: Error loading user:', error);
          localStorage.removeItem('token');
        })
        .finally(() => {
          setLoading(false);
        });
    } else {
      console.log('AuthContext: No token found');
      setLoading(false);
    }
  }, []);

  const login = async (username: string, password: string) => {
    try {
      const response = await authService.login(username, password);
      setUser(response.user);
      localStorage.setItem('token', response.token);

      // Return the user data so the component can handle navigation
      return response.user;
    } catch (error) {
      throw error;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('token');
    // Optionally clear other session data
  };

  const value: AuthContextType = {
    user,
    login,
    logout,
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
